// 利用率分析：每小时统计各桩使用率
@Scheduled(cron = "0 0 * * * ?")
public void calculateUtilization() {
    // 利用率 = 充电时长 / 总时长
    // 目标：提升整体利用率 > 60%
    String sql = """
        SELECT charger_id,
               SUM(TIMESTAMPDIFF(MINUTE, start_time, end_time)) / 60.0 as hours_used
