        // 90天未访问的数据 → 迁移到Glacier（成本降低90%）
        String sql = """
            UPDATE annotation_tasks
            SET storage_class = 'GLACIER'
            WHERE status = 'COMPLETED'
              AND updated_at < DATE_SUB(NOW(), INTERVAL 90 DAY)
              AND storage_class = 'STANDARD'
            """;
        // ...
    }
}
