        results['traffic_signs'] = signs

        # 自动标注置信度评分
        # 低置信度的标记为"需要人工审核"
        results['auto_confidence'] = calculate_confidence(results)
        results['needs_human'] = results['auto_confidence'] < 0.8

        return results
